# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import SwiftUI

@main
struct PromoLinkApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .onOpenURL { url in
                    UniversalLinkHandler.shared.handleUniversalLink(url)
                }
        }
    }
}

class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        UniversalLinkHandler.shared.handleUniversalLink(url)
        return true
    }
}

struct PromoCode: Codable, Identifiable {
    let id = UUID()
    let code: String
    let discount: Int
    let appliedDate: Date
    
    enum CodingKeys: String, CodingKey {
        case code, discount, appliedDate
    }
}

class UserAccount: ObservableObject {
    @Published var appliedPromoCodes: [PromoCode] = []
    @Published var currentDiscount: Int = 0
    
    static let shared = UserAccount()
    
    private let userDefaults = UserDefaults.standard
    private let promoCodesKey = "appliedPromoCodes"
    
    init() {
        loadPromoCodes()
    }
    
    func applyPromoCode(_ code: String, discount: Int) -> Bool {
        guard !hasAppliedPromoCode(code) else {
            return false
        }
        
        let promoCode = PromoCode(code: code, discount: discount, appliedDate: Date())
        appliedPromoCodes.append(promoCode)
        currentDiscount = calculateTotalDiscount()
        savePromoCodes()
        
        NotificationCenter.default.post(name: .promoCodeApplied, object: nil, userInfo: ["code": code, "discount": discount])
        
        return true
    }
    
    func hasAppliedPromoCode(_ code: String) -> Bool {
        return appliedPromoCodes.contains { $0.code.lowercased() == code.lowercased() }
    }
    
    private func calculateTotalDiscount() -> Int {
        let total = appliedPromoCodes.reduce(0) { $0 + $1.discount }
        return min(total, 100)
    }
    
    private func savePromoCodes() {
        if let encoded = try? JSONEncoder().encode(appliedPromoCodes) {
            userDefaults.set(encoded, forKey: promoCodesKey)
        }
    }
    
    private func loadPromoCodes() {
        if let data = userDefaults.data(forKey: promoCodesKey),
           let decoded = try? JSONDecoder().decode([PromoCode].self, from: data) {
            appliedPromoCodes = decoded
            currentDiscount = calculateTotalDiscount()
        }
    }
    
    func clearAllPromoCodes() {
        appliedPromoCodes.removeAll()
        currentDiscount = 0
        savePromoCodes()
    }
}

class UniversalLinkHandler: ObservableObject {
    static let shared = UniversalLinkHandler()
    
    @Published var lastPromoCode: String?
    @Published var lastDiscount: Int?
    @Published var showPromoAlert = false
    @Published var alertMessage = ""
    
    func handleUniversalLink(_ url: URL) {
        guard url.host == "myapp.com",
              url.path == "/promo" else {
            return
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            showError("Invalid promo link format")
            return
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value
            case "discount":
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            default:
                break
            }
        }
        
        guard let code = promoCode, !code.isEmpty,
              let discountValue = discount, discountValue > 0, discountValue <= 100 else {
            showError("Invalid promo code or discount value")
            return
        }
        
        applyPromoCode(code: code, discount: discountValue)
    }
    
    private func applyPromoCode(code: String, discount: Int) {
        let success = UserAccount.shared.applyPromoCode(code, discount: discount)
        
        DispatchQueue.main.async {
            self.lastPromoCode = code
            self.lastDiscount = discount
            
            if success {
                self.alertMessage = "Promo code '\(code)' applied successfully!\n\(discount)% discount added to your account."
            } else {
                self.alertMessage = "Promo code '\(code)' has already been applied to your account."
            }
            
            self.showPromoAlert = true
        }
    }
    
    private func showError(_ message: String) {
        DispatchQueue.main.async {
            self.alertMessage = message
            self.showPromoAlert = true
        }
    }
}

extension Notification.Name {
    static let promoCodeApplied = Notification.Name("promoCodeApplied")
}

